#include <bits/stdc++.h>
using namespace std;

static string compact_digits(istream& in) {
    string s, token;
    while (in >> token) s += token;
    return s;
}

int main(int argc, char** argv) {
    if (argc < 4) return 2;
    ifstream input(argv[1]), first(argv[2]);
    int mode, n;
    if (!(input >> mode >> n)) return 2;
    string s = compact_digits(first);
    if (s.empty() || s.size() > 6) return 1;
    for (char c : s) if (!isdigit((unsigned char)c)) return 1;

    random_device rd;
    mt19937 rng(rd() ^ chrono::steady_clock::now().time_since_epoch().count());
    uniform_int_distribution<int> pos_dist(0, (int)s.size() - 1);
    uniform_int_distribution<int> digit_dist(0, 9);
    int pos = pos_dist(rng);
    char old = s[pos];
    char neu = char('0' + digit_dist(rng));
    if (s.size() > 1) {
        for (int guard = 0; guard < 8 && neu == old; ++guard) neu = char('0' + digit_dist(rng));
    }
    s[pos] = neu;

    cout << 2 << ' ' << s << '\n';
    return 0;
}
